CREATE DATABASE IF NOT EXISTS luxe_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE luxe_db;
DROP TABLE IF EXISTS interactions,cart,orders,products,users;
CREATE TABLE users(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(100) NOT NULL,email VARCHAR(150) NOT NULL UNIQUE,password VARCHAR(255) NOT NULL,role ENUM('user','admin') DEFAULT 'user',email_verified TINYINT(1) DEFAULT 0,verify_token VARCHAR(64) DEFAULT NULL,verify_expires DATETIME DEFAULT NULL,created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE products(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(200) NOT NULL,description TEXT,price DECIMAL(10,2) NOT NULL,category VARCHAR(100),tag VARCHAR(50) DEFAULT 'Nouveau',stock INT DEFAULT 10,image_path VARCHAR(300) DEFAULT NULL,color VARCHAR(20) DEFAULT '#1a1a2e',rating DECIMAL(3,1) DEFAULT 4.5,reviews INT DEFAULT 0,created_at DATETIME DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE interactions(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NOT NULL,product_id INT NOT NULL,score INT DEFAULT 1,updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,UNIQUE KEY uq_inter(user_id,product_id),FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE,FOREIGN KEY(product_id) REFERENCES products(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE cart(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NOT NULL,product_id INT NOT NULL,qty INT DEFAULT 1,added_at DATETIME DEFAULT CURRENT_TIMESTAMP,UNIQUE KEY uq_cart(user_id,product_id),FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE,FOREIGN KEY(product_id) REFERENCES products(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE orders(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NOT NULL,total DECIMAL(10,2) NOT NULL,status ENUM('pending','confirmed','shipped','delivered') DEFAULT 'confirmed',created_at DATETIME DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS payments(id INT AUTO_INCREMENT PRIMARY KEY,order_id INT NOT NULL,user_id INT NOT NULL,stripe_pi_id VARCHAR(200) DEFAULT NULL,amount DECIMAL(10,2) NOT NULL,currency VARCHAR(3) DEFAULT 'eur',status ENUM('pending','succeeded','failed','refunded') DEFAULT 'pending',card_brand VARCHAR(20) DEFAULT NULL,card_last4 VARCHAR(4) DEFAULT NULL,created_at DATETIME DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(order_id) REFERENCES orders(id) ON DELETE CASCADE,FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE) ENGINE=InnoDB;
