INSERT INTO products(name,description,price,category,tag,stock,image_path,color,rating,reviews)VALUES('Montre Chronographe Noir','Montre de prestige alliant précision et élégance. Boîtier acier brossé, verre saphir.',2490,'Montres','Bestseller',15,'https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=600&q=80','#1a1a2e',4.8,124),('Sac Cuir Grain Milano','Sac artisanal en cuir pleine fleur, fabriqué à la main en Italie.',890,'Maroquinerie','Nouveau',8,'https://images.unsplash.com/photo-1548036328-c9fa89d128fa?w=600&q=80','#2e1a0e',4.9,89),('Parfum Oud Noir 100ml','Fragrance orientale intense, notes de bois de oud, ambre et musc blanc.',320,'Beauté','Exclusif',30,'https://images.unsplash.com/photo-1541643600914-78b084683702?w=600&q=80','#1a0e2e',4.7,203),('Veste Cachemire Gris','Veste en pur cachemire grade A, doublure soie naturelle, coupe ajustée.',1240,'Mode','Premium',12,'https://images.unsplash.com/photo-1551488831-00ddcb6c6bd3?w=600&q=80','#1e1e1e',4.6,67),('Sneakers Edition Limitée','Collaboration exclusive, semelle air, cuir nappa premium, numérotées.',480,'Chaussures','Limité',5,'https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=600&q=80','#0e1a2e',4.5,312),('Casque Audio Pro','Casque audiophile drivers 40mm, réduction bruit active, 30h autonomie.',750,'Tech','Top Vente',20,'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=600&q=80','#1a2e1a',4.8,445),('Ceinture Croco Noir','Ceinture en cuir embossé crocodile, boucle dorée 24k, made in France.',195,'Maroquinerie','Classique',25,'https://images.unsplash.com/photo-1624222247344-550fb60fe8ff?w=600&q=80','#1a1a0e',4.4,88),('Montre Plongée Bleue','Montre de plongée 300m étanche, mouvement automatique certifié COSC.',3200,'Montres','Luxe',4,'https://images.unsplash.com/photo-1434056886845-dac89ffe9b56?w=600&q=80','#0e1a2e',4.9,56),('Crème Caviar Prestige','Crème anti-âge à extrait de caviar et acide hyaluronique triple concentration.',280,'Beauté','Nouveau',18,'https://images.unsplash.com/photo-1596462502278-27bfdc403348?w=600&q=80','#2e2e1a',4.6,178),('Tablette Pro 12.9"','Tablette OLED 12.9 pouces, 256 Go, stylet magnétique inclus, 5G.',1890,'Tech','Pro',14,'https://images.unsplash.com/photo-1544244015-0df4b3ffc6b0?w=600&q=80','#1a1a2e',4.7,267),('Chaussures Oxford Tan','Derby en cuir de veau tanné végétal, semelle cuir Goodyear welt, England.',390,'Chaussures','Classique',9,'https://images.unsplash.com/photo-1533867617858-e7b97e060509?w=600&q=80','#2e1a0e',4.8,143),('Bracelet Manchette Argent','Manchette en argent 925 martelé à la main, ajustable, poinçon de maître.',340,'Bijoux','Argent',13,'https://images.unsplash.com/photo-1611085583191-a3b181a88401?w=600&q=80','#1a1e2e',4.8,76);
